586	MlirAttribute mlirCudaTileOptimizationHintsAttrGetEntryOpHint(
587	    MlirContext ctx, MlirStringRef arch, int32_t numCta, int32_t numWorkerWarps,
588	    int32_t occupancy) {
589	  auto context = unwrap(ctx);
590	  StringRef archStr = unwrap(arch);
591	
592	  // Build the inner dictionary with EntryOp hints
593	  SmallVector<NamedAttribute, 4> innerAttrs;
594	  IntegerType i32 = IntegerType::get(context, 32);
595	
596	  if (numCta != 0) {
597	    innerAttrs.emplace_back(StringAttr::get(context, "num_cta_in_cga"),
598	                            IntegerAttr::get(i32, numCta));
599	  }
600	
601	  if (numWorkerWarps != 0) {
602	    innerAttrs.emplace_back(
603	        StringAttr::get(context, "num_worker_warps_per_cta"),
604	        IntegerAttr::get(i32, numWorkerWarps));
605	  }
606	
607	  if (occupancy != 0) {
608	    innerAttrs.emplace_back(StringAttr::get(context, "occupancy"),
609	                            IntegerAttr::get(i32, occupancy));
610	  }
611	
612	  auto innerDict = DictionaryAttr::get(context, innerAttrs);
613	
614	  // Create the outer dictionary with architecture as key
615	  NamedAttribute outerEntry(StringAttr::get(context, archStr), innerDict);
616	  auto outerDict = DictionaryAttr::get(context, {outerEntry});
617	
618	  return wrap(OptimizationHintsAttr::get(context, outerDict));
619	}
