627	  SmallVector<NamedAttribute, 4> innerAttrs;
628	  IntegerType i32 = IntegerType::get(context, 32);
629	
630	  // Only emit allow_tma if explicitly specified (not -1)
631	  if (allowTma != -1) {
632	    innerAttrs.emplace_back(StringAttr::get(context, "allow_tma"),
633	                            BoolAttr::get(context, allowTma != 0));
634	  }
635	
636	  if (latency != 0) {
637	    innerAttrs.emplace_back(StringAttr::get(context, "latency"),
638	                            IntegerAttr::get(i32, latency));
639	  }
640	
641	  auto innerDict = DictionaryAttr::get(context, innerAttrs);
642	
643	  // Create the outer dictionary with architecture as key
644	  NamedAttribute outerEntry(StringAttr::get(context, archStr), innerDict);
645	  auto outerDict = DictionaryAttr::get(context, {outerEntry});
646	
647	  return wrap(OptimizationHintsAttr::get(context, outerDict));
648	}
