void mlirCudaTileOperationSetDiscardableAttributeByName(MlirOperation op,
                                                        MlirStringRef name,
                                                        MlirAttribute attr) {
  StringRef nameStr = unwrap(name);
  unwrap(op)->setDiscardableAttr(nameStr, unwrap(attr));
}

//===----------------------------------------------------------------------===//
